   128	    }
   129	
   130	    /// Render the status bar for a given width.
   131	    pub fn render(self: *const StatusBar, alloc: std.mem.Allocator, cols: u32, ctx: *const format.FormatContext) ![]u8 {
   132	        if (!self.enabled or cols == 0) {
   133	            return try alloc.alloc(u8, 0);
   134	        }
   135	
   136	        const left = try format.expand(alloc, self.left, ctx);
   137	        defer alloc.free(left);
   138	        const right = try format.expand(alloc, self.right, ctx);
   139	        defer alloc.free(right);
   140	
   141	        return self.renderSections(alloc, cols, left, "", right);
   142	    }
   143	
   144	    /// Render the status bar with explicit left/window-list/right sections.
   145	    pub fn renderSections(
   146	        self: *const StatusBar,
   147	        alloc: std.mem.Allocator,
   148	        cols: u32,
   149	        left: []const u8,
   150	        center: []const u8,
   151	        right: []const u8,
   152	    ) ![]u8 {
   153	        if (!self.enabled or cols == 0) {
   154	            return try alloc.alloc(u8, 0);
   155	        }
   156	
   157	        var leading: std.ArrayListAligned(u8, null) = .empty;
   158	        defer leading.deinit(alloc);
   159	
   160	        if (left.len > 0) {
   161	            try leading.appendSlice(alloc, left);
   162	        }
   163	        if (center.len > 0) {
   164	            if (leading.items.len > 0 and !endsWithVisibleSpace(leading.items) and !startsWithVisibleSpace(center)) {
   165	                try leading.append(alloc, ' ');
   166	            }
   167	            try leading.appendSlice(alloc, center);
   168	        }
   169	
   170	        var line: std.ArrayListAligned(u8, null) = .empty;
   171	        errdefer line.deinit(alloc);
   172	
   173	        const right_len = @min(visibleLen(right), cols);
   174	        const leading_budget = cols - right_len;
   175	        const leading_len = @min(visibleLen(leading.items), leading_budget);
   176	        var rendered_leading = try appendVisiblePrefix(alloc, &line, leading.items, leading_len);
   177	
   178	        while (rendered_leading < leading_budget) {
   179	            try line.append(alloc, ' ');
   180	            rendered_leading += 1;
   181	        }
   182	
   183	        _ = try appendVisiblePrefix(alloc, &line, right, right_len);
   184	
   185	        return try line.toOwnedSlice(alloc);
   186	    }
