    28	
    29	    const len = std.unicode.utf8ByteSequenceLength(input[0]) catch return null;
    30	    if (input.len < len) return null;
    31	
    32	    const cp = std.unicode.utf8Decode(input[0..len]) catch return null;
    33	
    34	    var result: Char = .{
